    Green = 2,
    Blue = 3
}

public static class ColorExtensions
{
    public static bool IsValid(this Color color)
    {
        return Enum.IsDefined(typeof(Color), color);
    }

    public static string ToDescription(this Color color)
    {
        return color.ToString();
    }
}
```

